/** Full-screen loading overlay with animated progress. */

let depth = 0;
let creepTimer = null;
let currentPct = 0;

function elements() {
  return {
    root: document.getElementById("screenLoader"),
    fill: document.getElementById("screenLoaderFill"),
    label: document.getElementById("screenLoaderLabel"),
    topBar: document.getElementById("loadingBar"),
    topFill: document.getElementById("loadingBarFill"),
  };
}

function applyProgress(pct) {
  currentPct = Math.max(currentPct, Math.min(pct, 100));
  const { fill, topFill, root } = elements();
  if (fill) fill.style.width = `${currentPct}%`;
  const bar = root?.querySelector("[role=progressbar]");
  if (bar) bar.setAttribute("aria-valuenow", String(Math.round(currentPct)));
  if (topFill) {
    const topBar = document.getElementById("loadingBar");
    topBar?.classList.remove("done");
    topFill.style.opacity = "1";
    topFill.style.width = `${currentPct}%`;
  }
}

function stopCreep() {
  if (!creepTimer) return;
  clearInterval(creepTimer);
  creepTimer = null;
}

function startCreep(from, to, ms) {
  stopCreep();
  const startAt = Date.now();
  creepTimer = setInterval(() => {
    const t = Math.min(1, (Date.now() - startAt) / ms);
    const eased = 1 - (1 - t) ** 2;
    applyProgress(from + (to - from) * eased);
    if (t >= 1) stopCreep();
  }, 40);
}

export function isScreenLoadActive() {
  return depth > 0;
}

export function beginScreenLoad(label = "Loading…") {
  depth += 1;
  const { root, label: labelEl } = elements();
  if (!root) return;
  if (depth === 1) {
    currentPct = 0;
    if (labelEl) labelEl.textContent = label;
    root.hidden = false;
    root.classList.remove("is-done");
    requestAnimationFrame(() => root.classList.add("is-visible"));
    applyProgress(10);
    startCreep(10, 78, 9000);
  } else if (labelEl) {
    labelEl.textContent = label;
  }
}

export function setScreenLoadProgress(pct) {
  stopCreep();
  applyProgress(pct);
  if (pct < 90) startCreep(pct, Math.min(pct + 12, 92), 5000);
}

export function endScreenLoad() {
  depth = Math.max(0, depth - 1);
  if (depth > 0) return;
  stopCreep();
  applyProgress(100);
  const { root } = elements();
  if (!root) return;
  root.classList.add("is-done");
  root.classList.remove("is-visible");
  document.getElementById("loadingBar")?.classList.add("done");
  window.setTimeout(() => {
    if (depth === 0) {
      root.hidden = true;
      root.classList.remove("is-done");
      currentPct = 0;
    }
  }, 420);
}

